// Generated by AI Assistant

import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import React from 'react';

import { AiProviderKeysEmptyState } from '@/pages/UserPreferences/AiProviderKeys/EmptyState';

describe('AiProviderKeysEmptyState', () => {
  it('should show admin message when no providers are configured', () => {
    render(
      <AiProviderKeysEmptyState isDisabled={false} hasProviders={false} onAddKey={jest.fn()} />,
    );

    expect(screen.getByText('No AI Providers Configured')).toBeDefined();
    expect(screen.getByText(/Ask your administrator/)).toBeDefined();
  });

  it('should show add key button when providers exist', () => {
    render(
      <AiProviderKeysEmptyState isDisabled={false} hasProviders={true} onAddKey={jest.fn()} />,
    );

    expect(screen.getByText('No AI Providers Keys')).toBeDefined();
    expect(screen.getByRole('button', { name: /Add AI Provider Key/i })).toBeDefined();
  });

  it('should call onAddKey when button is clicked', async () => {
    const onAddKey = jest.fn();
    render(<AiProviderKeysEmptyState isDisabled={false} hasProviders={true} onAddKey={onAddKey} />);

    await userEvent.click(screen.getByRole('button', { name: /Add AI Provider Key/i }));
    expect(onAddKey).toHaveBeenCalledTimes(1);
  });

  it('should disable add button when isDisabled is true', () => {
    render(<AiProviderKeysEmptyState isDisabled={true} hasProviders={true} onAddKey={jest.fn()} />);

    expect(screen.getByRole('button', { name: /Add AI Provider Key/i })).toBeDisabled();
  });
});
